    /** @type {number} */
    _exposure: number;
    /** @type {number} */
    _numSplats: number;
    /** @type {StorageBuffer|null} */
    _compactedSplatIds: StorageBuffer | null;
    /** @type {StorageBuffer|null} */
    _sortElementCountBuffer: StorageBuffer | null;
    /** @type {StorageBuffer|null} */
    _projCacheBuffer: StorageBuffer | null;
    /** @type {StorageBuffer|null} */
